mapper.update:
UPDATE daily_inspection_frequency
area_device_name = #{areaDeviceName}, inspection_content = #{inspectionContent}, inspection_standard = #{inspectionStandard}, data_type = #{dataType}, cycle_unit = #{cycleUnit}, frequency_value = #{frequencyValue}, month_date_set = #{monthDateSet}, week_date_set = #{weekDateSet}, shifts_set = #{shiftsSet}, maximums = #{maximums}, minimums = #{minimums}, updated_at = #{updatedAt},
WHERE id = #{id}

mapper.select:
SELECT dif.id, dif.daily_inspection_table_id AS dailyInspectionTableId, dif.frequency_code, dif.area_device_name, dif.inspection_content, dif.inspection_standard, dif.data_type, dif.cycle_unit, dif.frequency_value, dif.month_date_set, dif.week_date_set, dif.shifts_set, dif.maximums, dif.minimums, dif.creator_id, dif.created_at AS createdAt, dif.updated_at AS updatedAt, su.real_name AS creatorName, su.username AS creatorUsername FROM daily_inspection_frequency dif LEFT JOIN sys_user su ON dif.creator_id = su.id
AND dif.creator_id = #{creatorId}
AND dif.daily_inspection_table_id = #{dailyInspectionTableId}
AND dif.frequency_code LIKE CONCAT('%', #{frequencyCode}, '%')
AND dif.area_device_name LIKE CONCAT('%', #{areaDeviceName}, '%')
ORDER BY dif.id DESC

SELECT id, daily_inspection_table_id AS dailyInspectionTableId, frequency_code, area_device_name, inspection_content, inspection_standard, data_type, cycle_unit, frequency_value, month_date_set, week_date_set, shifts_set, maximums, minimums, creator_id, created_at AS createdAt, updated_at AS updatedAt FROM daily_inspection_frequency
AND creator_id = #{creatorId}
AND daily_inspection_table_id = #{dailyInspectionTableId}
AND frequency_code = #{frequencyCode}

mapper.delete:
DELETE FROM daily_inspection_frequency
WHERE id IN

    #{id}
